const wd = "/Users/zchee/go/src/github.com/zchee/spanner-manager";
const diff = await tools.shell_command({
  workdir: wd,
  command: [
    "printf '## git status\\n';",
    "git status --short;",
    "printf '\\n## modified files\\n';",
    "git diff --name-only;",
    "printf '\\n## diff -- codegen/generator_test.go\\n';",
    "git diff -- codegen/generator_test.go;",
    "printf '\\n## relevant template symbols\\n';",
    "rg --threads=8 -n \"columnsToPtrs|columnsToValues|values\\(\" codegen/type.go.tmpl codegen/generator_test.go || true;",
    "printf '\\n## type template excerpt\\n';",
    "sed -n '1,260p' codegen/type.go.tmpl;"
  ].join(" "),
  timeout_ms: 20000,
});
text(typeof diff === "string" ? diff : JSON.stringify(diff, null, 2));
